  "BWOMAN-SUBJECTS:TABLE": {
   "name": "BWOMAN-SUBJECTS:TABLE",
   "kind": "global",
   "file": "people.zil",
   "line": 298,
   "value": "<PLTABLE <PTABLE LCITY \"Lived 'ere all me life\"> <PTABLE LONDON \"Lived 'ere all me life\"> <PTABLE BALL \"Football! Sorry, hon, I'm too old to play\"> <PTABLE GRPOND \"It's just east o' here\"> <PTABLE LWATER \"A short walk east\"> <PTABLE VICTORIA \"Princess Louise carved it all herself, she did\"> <PTABLE GBAG \"Lovely bread crumbs, only thirty p a bag\"> <PTABLE BAG \"Lovely bread crumbs, only thirty p a bag\"> <PTABLE GNOMON \"A lovely bit o' metal! And so useful. Hold onto it, ducky\"> <PTABLE PIGEONS \"'Ave ye ever seen such beauties? So loyal. And so, so hungry\"> <PTABLE SCOIN \"That's yer change, ducky. Twenty p out of fifty\"> <PTABLE CREDIT-CARD \"I ain't Harrod's, dearie. Thirty p\"> <PTABLE PRAM \"All prams lead to Kensington Gardens, they say\"> <PTABLE BOY \"Lots o' boys around here, dearie\"> <PTABLE GRASS \"Humph!\" she sniffs. \"Never touch the stuff\"> <PTABLE CRANE \"Tidy bit o' foldin', that\"> <PTABLE OCRANE \"Looks a bit ragged to me\"> <PTABLE BAD-CRANE \"Looks a bit crumpled to me\"> <PTABLE PARASOL \"Ain't seen one like it in a long while\"> <PTABLE MEMORIAL \"Ghastly, ain't he? Everyone laughs\"> <PTABLE BWOMAN \"Me?\" The woman laughs and gestures at the pigeons. \"Here's all there is to know about me\"> <PTABLE GOON \"Shh!\" The old woman shudders. \"Ye musn't speak o' such things\">>"
  },
